#!/usr/bin/env node

/*
 * sync-html-templates.mjs
 *
 * Reads shared CSS/JS/HTML sources from lib/html-ui/ and generates
 * self-contained template files. All templates are deterministic:
 * same sources produce identical output.
 *
 * Do not edit generated templates directly.
 */

import { mkdirSync, readFileSync, writeFileSync } from 'node:fs';
import { dirname, resolve } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const root = resolve(__dirname, '..');

// ===== Source files =====

const uiDir = resolve(root, 'lib', 'html-ui');

function readPart(name) {
  const filePath = resolve(uiDir, name);
  try {
    return readFileSync(filePath, 'utf8');
  } catch (err) {
    throw new Error(
      `Failed to read source file "${name}" at "${filePath}" (uiDir: "${uiDir}"): ${err.message}`
    );
  }
}

const tokensCss = readPart('tokens.css');
const commonCss = readPart('common.css');
const brainstormCss = readPart('brainstorm.css');
const documentCss = readPart('document.css');
const documentThemeJs = readPart('document-theme.js');
const baseFrame = readPart('base-frame.html');

// ===== Output definitions =====

const BANNER = '<!-- Generated by scripts/sync-html-templates.mjs. Do not edit directly. -->\n';

const outputs = [
  {
    name: 'brainstorm',
    out: 'skills/brainstorming/scripts/frame-template.html',
    templateKind: 'brainstorm',
    bodyClass: '',
    title: 'Softpowers Brainstorming',
    styles: [tokensCss, commonCss, brainstormCss],
    scripts: '',
    header: `
<div class="sp-header">
  <h1><a href="https://github.com/bnema/softpowers" style="color: inherit; text-decoration: none;">Softpowers Brainstorming</a></h1>
  <div class="status">Connected</div>
</div>`,
    footer: `
<div class="indicator-bar">
  <span id="indicator-text">Click an option above, then return to the terminal</span>
</div>`,
  },
  {
    name: 'spec',
    out: 'templates/spec.template.html',
    templateKind: 'spec',
    bodyClass: 'sp-doc',
    title: '{{DOC_TITLE}}',
    styles: [tokensCss, commonCss, documentCss],
    scripts: documentThemeJs,
    header: `
<div class="sp-header">
  <h1><a href="https://github.com/bnema/softpowers" style="color: inherit; text-decoration: none;">Softpowers Spec</a></h1>
</div>`,
    footer: '',
  },
  {
    name: 'plan',
    out: 'templates/plan.template.html',
    templateKind: 'plan',
    bodyClass: 'sp-doc',
    title: '{{DOC_TITLE}}',
    styles: [tokensCss, commonCss, documentCss],
    scripts: documentThemeJs,
    header: `
<div class="sp-header">
  <h1><a href="https://github.com/bnema/softpowers" style="color: inherit; text-decoration: none;">Softpowers Plan</a></h1>
</div>`,
    footer: '',
  },
];

function inlineCss(parts) {
  return parts.join('\n\n');
}

function buildTemplate(def) {
  const styleBlock = '<style>\n' + inlineCss(def.styles) + '\n</style>';
  const scriptBlock = def.scripts ? '<script>\n' + def.scripts + '\n</script>' : '';

  // The brainstorming server expects <!-- CONTENT --> (HTML comment), not {{CONTENT}}.
  // Additionally, the server test asserts id="claude-content" on the container.
  // Spec and plan templates both emit pre-structured document shells with stable placeholders.
  let contentPlaceholder;
  if (def.name === 'brainstorm') {
    contentPlaceholder = '<div id="claude-content"><!-- CONTENT --></div>';
  } else if (def.name === 'spec') {
    contentPlaceholder = `<article class="sp-document sp-spec" data-doc-kind="spec" data-doc-version="1">
  <header class="sp-doc-header">
    <p class="sp-eyebrow">Softpowers Spec</p>
    <h1 id="top">{{DOC_TITLE}}</h1>
    <button id="theme-toggle" class="theme-toggle" type="button">Toggle theme</button>
  </header>
  <nav class="sp-toc" aria-label="Table of contents">{{TOC_ITEMS}}</nav>
  <section id="overview" data-section="overview">{{OVERVIEW}}</section>
</article>`;
  } else if (def.name === 'plan') {
    contentPlaceholder = `<article class="sp-document sp-plan" data-doc-kind="plan" data-doc-version="1">
  <header class="sp-doc-header">
    <p class="sp-eyebrow">Softpowers Plan</p>
    <h1 id="top">{{DOC_TITLE}}</h1>
    <button id="theme-toggle" class="theme-toggle" type="button">Toggle theme</button>
  </header>
  <nav class="sp-toc" aria-label="Table of contents">{{TOC_ITEMS}}</nav>
  <section id="phase-1" class="sp-phase" data-phase-id="phase-1">
    <header class="sp-phase-header">
      <h2>{{PHASE_TITLE}}</h2>
      <p class="sp-phase-goal">{{PHASE_GOAL}}</p>
    </header>
    <article id="task-1" class="sp-task" data-task-id="task-1">
      <ol class="sp-step-list">
        <li id="step-1" class="sp-step" data-step-id="step-1" data-step-kind="implementation" data-file="{{STEP_FILE}}" data-lines="{{STEP_LINES}}" data-command="{{VERIFY_COMMAND}}">
          <h4>{{STEP_TITLE}}</h4>
          <a class="sp-spec-link" href="{{SPEC_PATH}}#{{SPEC_SECTION}}">See spec rationale</a>
          <div class="sp-verify-block"><code>{{VERIFY_COMMAND}}</code></div>
          <div class="sp-watchouts">{{STEP_WATCHOUTS}}</div>
        </li>
      </ol>
    </article>
  </section>
</article>`;
  } else {
    contentPlaceholder = '{{CONTENT}}';
  }

  let html = baseFrame
    .replace('{{DOC_TITLE}}', def.title)
    .replace('{{STYLES}}', styleBlock)
    .replace('{{HEAD_EXTRAS}}', '')
    .replace('{{BODY_CLASS}}', def.bodyClass)
    .replace('{{TEMPLATE_KIND}}', def.templateKind)
    .replace('{{HEADER}}', def.header)
    .replace('{{CONTENT}}', contentPlaceholder)
    .replace('{{FOOTER}}', def.footer)
    .replace('{{SCRIPTS}}', scriptBlock);

  return BANNER + html.trim() + '\n';
}

// ===== Generate =====

for (const def of outputs) {
  const outPath = resolve(root, def.out);
  try {
    mkdirSync(dirname(outPath), { recursive: true });
    writeFileSync(outPath, buildTemplate(def), 'utf8');
    console.log('Wrote: ' + def.out);
  } catch (err) {
    throw new Error(
      `Failed to write output "${def.out}" at "${outPath}": ${err.message}`
    );
  }
}

console.log('Done.');
